using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    // Read the description field from the same multipart form
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var path = Path.Combine("uploads", file.FileName);
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);
        saved.Add(file.FileName);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery()                          // required for minimal APIs accepting forms
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);  // form-level limit

app.Run();
```

**Key points:**

- `IFormFileCollection` binds all files from the `<input type="file" multiple>` field.
- `.WithRequestFormLimits(...)` raises the per-endpoint multipart limit (default is ~128 MB but Kestrel's body limit is 30 MB).
- `.DisableAntiforgery()` is needed in .NET 8+ minimal APIs that accept form data without an antiforgery token.
- The text field (`description`) is read from `request.Form` since it's part of the same multipart payload.

**Example `curl` to test:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png" \
  -F "description=Vacation photos"
```
